INSERT INTO public.spmo_change_requests VALUES (1, 195, 'Scope extension — 40 additional detection nodes', 'Traffic data analysis revealed 40 additional camera positions required on secondary roads not in original scope. Failure to include these will result in 22% coverage gap against the 100% target KPI.', 'scope', 'Significant budget and timeline increase. Phase 2 nodes add SAR 4.5M and extend delivery by 4 months.', '56298317', 'Hany Al-Rashidi', '2026-03-24 09:41:11.873544+00', 'pending', NULL, NULL, NULL, NULL, 4.5e+06, 16, '2026-03-24 09:41:11.873544+00', '2026-03-24 09:41:11.873544+00');
INSERT INTO public.spmo_change_requests VALUES (2, 200, 'Revised BOQ — civil works cost escalation', 'Global steel and concrete price increases since original estimate (Jan 2024) have raised the BOQ by SAR 3.3M. Requesting budget amendment to avoid scope reduction.', 'budget', 'Budget increase of SAR 3.3M required; no timeline impact if approved within 30 days.', '56298317', 'Hany Al-Rashidi', '2026-03-24 09:41:11.873544+00', 'approved', NULL, NULL, NULL, NULL, 3.3e+06, 0, '2026-03-24 09:41:11.873544+00', '2026-03-24 09:41:11.873544+00');
INSERT INTO public.spmo_change_requests VALUES (3, 215, 'Defer dynamic pricing implementation by one quarter', 'Legal review has identified the need for a bilateral agreement amendment before price variance bands can be activated. Requesting a Q3 → Q4 2026 go-live shift.', 'timeline', 'No budget impact; timeline deferred by 3 months.', '56298317', 'Hany Al-Rashidi', '2026-03-24 09:41:11.873544+00', 'approved', NULL, NULL, NULL, NULL, 0, 90, '2026-03-24 09:41:11.873544+00', '2026-03-24 09:41:11.873544+00');
INSERT INTO public.spmo_change_requests VALUES (4, 228, 'Add change management workstream to restructuring project', 'Following mid-point risk assessment, a dedicated change management workstream (external consultant) is recommended to reduce staff resistance risk.', 'scope', 'Additional SAR 1.5M for 6-month change management engagement.', '56298317', 'Hany Al-Rashidi', '2026-03-24 09:41:11.873544+00', 'pending', NULL, NULL, NULL, NULL, 1.5e+06, 0, '2026-03-24 09:41:11.873544+00', '2026-03-24 09:41:11.873544+00');
INSERT INTO public.spmo_change_requests VALUES (5, 251, 'Integrate TMS data with external MOMRA road authority API', 'Ministry of Roads (MOMRA) has offered a real-time traffic feed that would significantly enhance TMS predictive accuracy. Additional integration work estimated at 6 weeks.', 'scope', 'Minimal cost (SAR 180,000 integration effort); 6-week schedule extension requested.', '56298317', 'Hany Al-Rashidi', '2026-03-24 09:41:11.873544+00', 'pending', NULL, NULL, NULL, NULL, 180000, 42, '2026-03-24 09:41:11.873544+00', '2026-03-24 09:41:11.873544+00');
INSERT INTO public.spmo_change_requests VALUES (6, 235, 'Expand cybersecurity assessment to include OT/SCADA systems', 'CISO has determined that the original scope (IT only) is insufficient. OT/SCADA systems control toll gates and must be included to satisfy NCA regulatory requirements.', 'scope', 'Assessment scope increase adds SAR 280,000 and 3 weeks to the engagement.', '56298317', 'Hany Al-Rashidi', '2026-03-24 09:41:11.873544+00', 'approved', NULL, NULL, NULL, NULL, 280000, 21, '2026-03-24 09:41:11.873544+00', '2026-03-24 09:41:11.873544+00');
