INSERT INTO public.spmo_risks VALUES (1, 14, 187, 'Customer journey mapping stalls due to stakeholder disagreement', 'Conflicting priorities between operations and CX teams may delay agreement on the target state journey map.', 'medium', 'high', 12, 'Head of Customer Experience', 'open', '2026-03-24 09:41:11.873544+00', '2026-03-24 09:41:11.873544+00', 'operational');
INSERT INTO public.spmo_risks VALUES (2, 15, 195, 'Road incident detection system integration failure', 'Legacy SCADA infrastructure may be incompatible with the new real-time detection platform, causing prolonged integration delays.', 'medium', 'critical', 16, 'Head of Technology', 'open', '2026-03-24 09:41:11.873544+00', '2026-03-24 09:41:11.873544+00', 'technical');
INSERT INTO public.spmo_risks VALUES (3, 15, 196, 'Supply delays for border lighting equipment', 'Global semiconductor shortages could extend delivery timelines for smart lighting controllers by 3–6 months.', 'high', 'high', 15, 'Head of Projects', 'open', '2026-03-24 09:41:11.873544+00', '2026-03-24 09:41:11.873544+00', 'procurement');
INSERT INTO public.spmo_risks VALUES (4, 16, 215, 'Dynamic pricing model regulatory non-compliance', 'Proposed toll price variance ranges may conflict with bilateral KFCA–Saudi agreement pricing caps.', 'low', 'critical', 12, 'Head of Legal & Compliance', 'open', '2026-03-24 09:41:11.873544+00', '2026-03-24 09:41:11.873544+00', 'compliance');
INSERT INTO public.spmo_risks VALUES (5, 17, 228, 'Organisation restructure resistance from middle management', 'Key department heads may resist changes to reporting lines, causing delays in the new operating model activation.', 'medium', 'medium', 9, 'Head of HR', 'mitigated', '2026-03-24 09:41:11.873544+00', '2026-03-24 09:41:11.873544+00', 'organizational');
INSERT INTO public.spmo_risks VALUES (6, 18, 244, 'On-time performance incentive scheme gaming', 'Carriers may manipulate reporting to falsely qualify for incentives without genuine improvements to punctuality.', 'low', 'high', 8, 'Head of Operations', 'open', '2026-03-24 09:41:11.873544+00', '2026-03-24 09:41:11.873544+00', 'financial');
INSERT INTO public.spmo_risks VALUES (7, 19, 251, 'TMS vendor lock-in risk', 'The selected TMS platform uses proprietary APIs making future migration costly and technically complex.', 'medium', 'high', 12, 'Head of Technology', 'open', '2026-03-24 09:41:11.873544+00', '2026-03-24 09:41:11.873544+00', 'technical');
INSERT INTO public.spmo_risks VALUES (8, 19, 235, 'Cybersecurity maturity assessment scope creep', 'Expanding audit scope mid-engagement with the third-party assessor may exceed budget and timeline.', 'high', 'medium', 12, 'CISO', 'open', '2026-03-24 09:41:11.873544+00', '2026-03-24 09:41:11.873544+00', 'operational');
INSERT INTO public.spmo_risks VALUES (9, 20, 228, 'Talent retention risk during restructuring', 'High-performing staff may accept competitor offers while the restructuring creates uncertainty about career paths.', 'medium', 'high', 12, 'Head of HR', 'open', '2026-03-24 09:41:11.873544+00', '2026-03-24 09:41:11.873544+00', 'organizational');
INSERT INTO public.spmo_risks VALUES (10, 22, 223, 'Investment optimisation programme deliverable quality', 'External consultants may deliver generic recommendations without sufficient KFCA-specific context.', 'medium', 'medium', 9, 'Head of Strategy', 'open', '2026-03-24 09:41:11.873544+00', '2026-03-24 09:41:11.873544+00', 'operational');
INSERT INTO public.spmo_risks VALUES (11, 14, 190, 'Customer care centralisation — data migration risk', 'CRM data migration from regional systems to the centralised platform carries a risk of data loss or corruption.', 'low', 'critical', 12, 'Head of IT', 'open', '2026-03-24 09:41:11.873544+00', '2026-03-24 09:41:11.873544+00', 'technical');
INSERT INTO public.spmo_risks VALUES (12, 15, 200, 'Maintenance yard upgrade — budget overrun', 'Preliminary bills of quantities may be understated by 15–20% based on recent regional construction cost inflation.', 'high', 'high', 15, 'Head of Finance', 'open', '2026-03-24 09:41:11.873544+00', '2026-03-24 09:41:11.873544+00', 'financial');
INSERT INTO public.spmo_risks VALUES (13, 16, 217, 'Digital payments incentivisation — low uptake', 'If the initial cashback model is not compelling enough, adoption targets for digital toll payments may not be met.', 'medium', 'medium', 9, 'Head of Commercial', 'open', '2026-03-24 09:41:11.873544+00', '2026-03-24 09:41:11.873544+00', 'strategic');
INSERT INTO public.spmo_risks VALUES (14, 18, 245, 'Pre-registration system — traveller privacy concerns', 'Mandatory biometric data collection for the pre-registration pilot may attract negative media coverage.', 'low', 'high', 8, 'Head of Communications', 'open', '2026-03-24 09:41:11.873544+00', '2026-03-24 09:41:11.873544+00', 'reputational');
INSERT INTO public.spmo_risks VALUES (15, 21, 225, 'Strategy communication plan — message misalignment', 'Inconsistent messaging across Arabic and English channels could undermine the KFCA brand narrative.', 'medium', 'medium', 9, 'Head of Branding', 'open', '2026-03-24 09:41:11.873544+00', '2026-03-24 09:41:11.873544+00', 'reputational');
